        private static CustomBinding CreateSecureBinding()
        {
            var security = new AsymmetricSecurityBindingElement
            {
                MessageSecurityVersion = MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10,
                InitiatorTokenParameters = new X509SecurityTokenParameters
                {
                    InclusionMode = SecurityTokenInclusionMode.AlwaysToRecipient,
                    RequireDerivedKeys = false
                },
                RecipientTokenParameters = new X509SecurityTokenParameters
                {
                    InclusionMode = SecurityTokenInclusionMode.Never,
                    RequireDerivedKeys = false
                },
                MessageProtectionOrder = MessageProtectionOrder.SignBeforeEncrypt,
                SecurityHeaderLayout = SecurityHeaderLayout.Strict,
                IncludeTimestamp = true,
                AllowSerializedSigningTokenOnReply = true,
                RequireSignatureConfirmation = false
            };

            security.LocalClientSettings.DetectReplays = true;
            security.LocalClientSettings.ReplayWindow = TimeSpan.FromMinutes(5);
            security.LocalClientSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
            security.LocalClientSettings.TimestampValidityDuration = TimeSpan.FromMinutes(5);

            security.LocalServiceSettings.DetectReplays = true;
            security.LocalServiceSettings.ReplayWindow = TimeSpan.FromMinutes(5);
            security.LocalServiceSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
            security.LocalServiceSettings.TimestampValidityDuration = TimeSpan.FromMinutes(5);

            var encoding = new TextMessageEncodingBindingElement
            {
                MessageVersion = MessageVersion.Soap12WSAddressing10,
                WriteEncoding = Encoding.UTF8
            };

            var transport = new HttpsTransportBindingElement
            {
                MaxReceivedMessageSize = 2147483647,
                RequireClientCertificate = true
            };

            var binding = new CustomBinding(security, encoding, transport);
            binding.SendTimeout = TimeSpan.FromMinutes(10);
            binding.ReceiveTimeout = TimeSpan.FromMinutes(10);

            return binding;
        }

        private static void ConfigureServiceCredentials(ServiceHost serviceHost)
        {
            var serviceCredentials = serviceHost.Description.Behaviors.Find<ServiceCredentials>();
            if (serviceCredentials == null)
            {
                serviceCredentials = new ServiceCredentials();
                serviceHost.Description.Behaviors.Add(serviceCredentials);
            }

            var serverCert = GetServerCertificate();
            serviceCredentials.ServiceCertificate.Certificate = serverCert;

            serviceCredentials.ClientCertificate.Authentication.CertificateValidationMode = X509CertificateValidationMode.Custom;
            serviceCredentials.ClientCertificate.Authentication.CustomCertificateValidator = new CustomX509CertificateValidator();
            serviceCredentials.ClientCertificate.Authentication.RevocationMode = X509RevocationMode.Online;
        }

        private static X509Certificate2 GetServerCertificate()
        {
            using (var store = new X509Store(StoreName.My, StoreLocation.LocalMachine))
            {
                store.Open(OpenFlags.ReadOnly);
                var certs = store.Certificates.Find(X509FindType.FindBySubjectName, "localhost", false);
                
                if (certs.Count > 0)
                {
                    return certs[0];
                }
            }

            return GenerateSelfSignedCertificate();
        }

        private static X509Certificate2 GenerateSelfSignedCertificate()
        {
            using (var rsa = RSA.Create(4096))
            {
                var request = new CertificateRequest(
                    "CN=localhost",
                    rsa,
                    HashAlgorithmName.SHA256,
                    RSASignaturePadding.Pkcs1);

                request.CertificateExtensions.Add(
                    new X509KeyUsageExtension(
                        X509KeyUsageFlags.DataEncipherment | X509KeyUsageFlags.KeyEncipherment | X509KeyUsageFlags.DigitalSignature,
                        false));

                request.CertificateExtensions.Add(
                    new X509EnhancedKeyUsageExtension(
                        new OidCollection { new Oid("1.3.6.1.5.5.7.3.1") },
                        false));

                var sanBuilder = new SubjectAlternativeNameBuilder();
                sanBuilder.AddDnsName("localhost");
                request.CertificateExtensions.Add(sanBuilder.Build());

                var certificate = request.CreateSelfSigned(
                    DateTimeOffset.Now.AddDays(-1),
                    DateTimeOffset.Now.AddYears(5));

                return new X509Certificate2(
                    certificate.Export(X509ContentType.Pfx, "password"),
                    "password",
                    X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.PersistKeySet | X509KeyStorageFlags.Exportable);
            }
        }
    }

